router.put('/tasks/:id/labels', (req, res, next) => {
  try {
    validateId(req.params.id);
    const task = Task.findById(req.params.id);
    if (!task) throw new ApiError('Task not found', 404);
    if (!Array.isArray(req.body.labels) || !req.body.labels.every(label => typeof label === 'string' && label.trim())) {
      throw new ApiError('Labels must be a non-empty array of strings', 400);
    }
    task.labels = req.body.labels;
    task.updatedAt = new Date().toISOString();
    return res.json(task);
  } catch (err) { return next(err); }
});
